'use client'

import { Notification } from '../../types'
import { FiBell, FiTrash2, FiSend, FiEye, FiCalendar } from 'react-icons/fi'
import { Loader } from '../../components/common/Loader'

interface NotificationListProps {
  notifications: Notification[]
  loading: boolean
  onDelete: (notificationId: string) => void
  onResend: (notificationId: string) => void
}

export function NotificationList({ notifications, loading, onDelete, onResend }: NotificationListProps) {
  if (loading) {
    return <Loader message="Loading notifications..." />
  }

  if (notifications.length === 0) {
    return (
      <div className="text-center py-12">
        <FiBell className="mx-auto text-4xl text-text-light mb-4" />
        <p className="text-text">No notifications found</p>
        <p className="text-text-light">Create your first notification to get started</p>
      </div>
    )
  }

  const getTypeBadge = (type: string) => {
    switch (type) {
      case 'banner': return 'bg-blue-100 text-blue-800'
      case 'fullscreen': return 'bg-purple-100 text-purple-800'
      default: return 'bg-gray-100 text-gray-800'
    }
  }

  const getTargetBadge = (target: string) => {
    switch (target) {
      case 'all': return 'bg-green-100 text-green-800'
      case 'location': return 'bg-yellow-100 text-yellow-800'
      case 'search_history': return 'bg-indigo-100 text-indigo-800'
      default: return 'bg-gray-100 text-gray-800'
    }
  }

  return (
    <div className="space-y-4">
      {notifications.map((notification) => (
        <div
          key={notification.id}
          className="border border-border rounded-lg p-4 hover:shadow-md transition-shadow"
        >
          <div className="flex items-start justify-between">
            <div className="flex-1">
              <div className="flex items-center space-x-3 mb-2">
                <h4 className="font-semibold text-text">{notification.title}</h4>
                <span className={`text-xs px-2 py-1 rounded-full ${getTypeBadge(notification.type)}`}>
                  {notification.type.toUpperCase()}
                </span>
                <span className={`text-xs px-2 py-1 rounded-full ${getTargetBadge(notification.target_type)}`}>
                  {notification.target_type.replace('_', ' ').toUpperCase()}
                </span>
              </div>
              
              <p className="text-text-light mb-3">{notification.message}</p>
              
              <div className="flex items-center space-x-6 text-sm text-text-light">
                <div className="flex items-center">
                  <FiSend className="mr-2" />
                  <span>Sent: {notification.sent_count}</span>
                </div>
                <div className="flex items-center">
                  <FiEye className="mr-2" />
                  <span>Read: {notification.read_count}</span>
                </div>
                <div className="flex items-center">
                  <FiCalendar className="mr-2" />
                  <span>{new Date(notification.created_at).toLocaleDateString()}</span>
                </div>
              </div>
            </div>
            
            <div className="flex items-center space-x-2 ml-4">
              <button
                onClick={() => onResend(notification.id)}
                className="p-2 text-primary hover:bg-primary/10 rounded-lg"
                title="Resend"
              >
                <FiSend />
              </button>
              <button
                onClick={() => onDelete(notification.id)}
                className="p-2 text-error hover:bg-error/10 rounded-lg"
                title="Delete"
              >
                <FiTrash2 />
              </button>
            </div>
          </div>
          
          {notification.target_criteria && Object.keys(notification.target_criteria).length > 0 && (
            <div className="mt-4 pt-4 border-t border-border">
              <p className="text-sm text-text-light mb-2">Target Criteria:</p>
              <div className="flex flex-wrap gap-2">
                {Object.entries(notification.target_criteria).map(([key, value]) => (
                  <span key={key} className="text-xs px-2 py-1 bg-gray-100 text-gray-800 rounded">
                    {key}: {Array.isArray(value) ? value.join(', ') : value}
                  </span>
                ))}
              </div>
            </div>
          )}
        </div>
      ))}
    </div>
  )
}